using Microsoft.AspNetCore.Diagnostics;
using Microsoft.AspNetCore.Mvc;

namespace YourApp;

public class GlobalExceptionHandler : IExceptionHandler
{
    private readonly ILogger<GlobalExceptionHandler> _logger;

    public GlobalExceptionHandler(ILogger<GlobalExceptionHandler> logger)
    {
        _logger = logger;
    }

    public async ValueTask<bool> TryHandleAsync(
        HttpContext httpContext,
        Exception exception,
        CancellationToken cancellationToken)
    {
        var (statusCode, title) = exception switch
        {
            KeyNotFoundException => (StatusCodes.Status404NotFound, "Resource Not Found"),
            ArgumentException => (StatusCodes.Status400BadRequest, "Bad Request"),
            InvalidOperationException => (StatusCodes.Status409Conflict, "Conflict"),
            _ => (StatusCodes.Status500InternalServerError, "Internal Server Error")
        };

        _logger.LogError(exception, "Exception occurred: {Message}", exception.Message);

        var problemDetails = new ProblemDetails
        {
            Status = statusCode,
            Title = title,
            Detail = statusCode == StatusCodes.Status500InternalServerError
                ? "An unexpected error occurred."  // Hide sensitive details
                : exception.Message,
            Instance = httpContext.Request.Path
        };

        httpContext.Response.StatusCode = statusCode;
        await httpContext.Response.WriteAsJsonAsync(problemDetails, cancellationToken);

        return true; // Signal that we handled the exception
    }
}

using YourApp;

var builder = WebApplication.CreateBuilder(args);

// Register Problem Details services and the global exception handler
builder.Services.AddProblemDetails();
builder.Services.AddExceptionHandler<GlobalExceptionHandler>();

var app = builder.Build();

// Add the exception handler middleware (must be early in the pipeline)
app.UseExceptionHandler();

// Example endpoints to demonstrate behavior
app.MapGet("/items/{id}", (int id) =>
{
    if (id < 0) throw new ArgumentException("ID must be non-negative.");
    if (id == 0) throw new KeyNotFoundException("Item not found.");
    if (id == 99) throw new InvalidOperationException("Item is in a conflicting state.");
    if (id == 100) throw new Exception("Something unexpected broke.");

    return Results.Ok(new { Id = id, Name = "Sample Item" });
});

app.Run();

